@login_required
@permission_required('clientes.change_cliente', raise_exception=True)
def cliente_toggle_estado(request, pk):
    """Activar/Desactivar cliente"""
    empresa, error = obtener_empresa_usuario(request)
    if error:
        messages.error(request, error)
        return redirect('clientes:cliente_list')
    
    cliente = get_object_or_404(Cliente, pk=pk, empresa=empresa)
    
    if cliente.estado == 'activo':
        cliente.estado = 'inactivo'
        messages.success(request, f'Cliente "{cliente.nombre}" desactivado exitosamente.')
    else:
        cliente.estado = 'activo'
        messages.success(request, f'Cliente "{cliente.nombre}" activado exitosamente.')
    
    cliente.save()
    return redirect('clientes:cliente_list')


@login_required
@permission_required('clientes.add_contactocliente', raise_exception=True)
def contacto_create(request, cliente_id):
    """Crear contacto en modal"""
    cliente = get_object_or_404(Cliente, id=cliente_id)
    
    if request.method == 'POST':
        form = ContactoClienteForm(request.POST)
        if form.is_valid():
            contacto = form.save(commit=False)
            contacto.cliente = cliente
            contacto.save()
            messages.success(request, 'Contacto agregado exitosamente.')
            return redirect('clientes:cliente_detail', pk=cliente.id)
    else:
        form = ContactoClienteForm()
    
    context = {
        'form': form,
        'cliente': cliente,
    }
    
    return render(request, 'clientes/contacto_form_modal.html', context)


@login_required
@permission_required('clientes.change_contactocliente', raise_exception=True)
def contacto_update(request, cliente_id, contacto_id):
    """Editar contacto en modal"""
    cliente = get_object_or_404(Cliente, id=cliente_id)
    contacto = get_object_or_404(ContactoCliente, id=contacto_id, cliente=cliente)
    
    if request.method == 'POST':
        form = ContactoClienteForm(request.POST, instance=contacto)
        if form.is_valid():
            form.save()
            messages.success(request, 'Contacto actualizado exitosamente.')
            return redirect('clientes:cliente_detail', pk=cliente.id)
    else:
        form = ContactoClienteForm(instance=contacto)
    
    context = {
        'form': form,
        'cliente': cliente,
        'contacto': contacto,
    }
    
    return render(request, 'clientes/contacto_form_modal.html', context)


@login_required
@permission_required('clientes.delete_contactocliente', raise_exception=True)
def contacto_delete(request, cliente_id, contacto_id):
    """Eliminar contacto"""
    cliente = get_object_or_404(Cliente, id=cliente_id)
    contacto = get_object_or_404(ContactoCliente, id=contacto_id, cliente=cliente)
    
    if request.method == 'POST':
        nombre = contacto.nombre
        contacto.delete()
        messages.success(request, f'Contacto "{nombre}" eliminado exitosamente.')
        return redirect('clientes:cliente_detail', pk=cliente.id)
    
    context = {
        'cliente': cliente,
        'contacto': contacto,
    }
    
    return render(request, 'clientes/contacto_confirm_delete.html', context)

@login_required
def ajax_vendedores(request):
    """Obtener lista de vendedores para los modales"""
    empresa, error = obtener_empresa_usuario(request)
    if error:
        return JsonResponse({'success': False, 'message': error}, status=400)
    
    from ventas.models import Vendedor
    vendedores = Vendedor.objects.filter(empresa=empresa, activo=True).values('id', 'nombre')
    return JsonResponse({'success': True, 'vendedores': list(vendedores)})

@login_required
def ajax_cliente_contactos(request, pk):
    """Obtener lista de contactos de un cliente"""
    cliente = get_object_or_404(Cliente, id=pk)
    contactos = cliente.contactos.all().values('id', 'nombre', 'cargo', 'tipo_contacto', 'telefono', 'celular', 'email', 'es_contacto_principal')
    return JsonResponse({'success': True, 'contactos': list(contactos)})

@login_required
def ajax_cliente_create(request):
    """Crear cliente v챠a AJAX"""
    if not request.user.has_perm('clientes.add_cliente'):
        return JsonResponse({'success': False, 'message': 'No tiene permiso para crear clientes.'}, status=403)
        
    if request.method == 'POST':
        empresa, error = obtener_empresa_usuario(request)
        if error:
            return JsonResponse({'success': False, 'message': error}, status=400)
            
        form = ClienteForm(request.POST, empresa=empresa)
        if form.is_valid():
            try:
                cliente = form.save(commit=False)
                cliente.empresa = empresa
                cliente.save()
                return JsonResponse({'success': True, 'message': 'Cliente creado correctamente', 'id': cliente.id, 'nombre': cliente.nombre, 'rut': cliente.get_rut_formateado()})
            except Exception as e:
                return JsonResponse({'success': False, 'message': str(e)}, status=500)
        else:
            errors = []
            for field, f_errors in form.errors.items():
                field_label = form.fields[field].label if field in form.fields else field
                errors.append(f"{field_label}: {', '.join(f_errors)}")
            return JsonResponse({'success': False, 'message': 'Error de validaci처n:\n' + '\n'.join(errors)}, status=400)
    return JsonResponse({'success': False, 'message': 'M챕todo no permitido'}, status=405)

@login_required
def ajax_cliente_detail(request, pk):
    """Obtener datos de un cliente"""
    if not request.user.has_perm('clientes.view_cliente'):
        return JsonResponse({'success': False, 'message': 'No tiene permiso para ver clientes.'}, status=403)
        
    cliente = get_object_or_404(Cliente, id=pk)
    return JsonResponse({
        'success': True,
        'cliente': {
            'id': cliente.id,
            'rut': cliente.rut,
            'nombre': cliente.nombre,
            'giro': cliente.giro or '',
            'direccion': cliente.direccion or '',
            'comuna': cliente.comuna or '',
            'ciudad': cliente.ciudad or '',
            'region': cliente.region or '',
            'telefono': cliente.telefono or '',
            'email': cliente.email or '',
            'tipo_cliente': cliente.tipo_cliente,
            'vendedor': cliente.vendedor.id if cliente.vendedor else None,
            'vendedor_nombre': cliente.vendedor.nombre if cliente.vendedor else 'Sin vendedor',
            'ruta': cliente.ruta.id if cliente.ruta else None,
            'ruta_nombre': cliente.ruta.nombre if cliente.ruta else 'Sin ruta',
            'descuento_porcentaje': float(cliente.descuento_porcentaje or 0),
            'limite_credito': float(cliente.limite_credito or 0),
            'plazo_pago': cliente.plazo_pago or 30,
            'estado': cliente.estado,
            'observaciones': cliente.observaciones or ''
        }
    })

@login_required
def ajax_cliente_update(request, pk):
    """Actualizar cliente"""
    if not request.user.has_perm('clientes.change_cliente'):
        return JsonResponse({'success': False, 'message': 'No tiene permiso para editar clientes.'}, status=403)
        
    if request.method == 'POST':
        empresa, error = obtener_empresa_usuario(request)
        if error:
            return JsonResponse({'success': False, 'message': error}, status=400)
            
        cliente = get_object_or_404(Cliente, id=pk)
        form = ClienteForm(request.POST, instance=cliente, empresa=empresa)
        if form.is_valid():
            try:
                cliente = form.save()
                return JsonResponse({'success': True, 'message': 'Cliente actualizado correctamente', 'id': cliente.id, 'nombre': cliente.nombre})
            except Exception as e:
                return JsonResponse({'success': False, 'message': str(e)}, status=500)
        else:
            errors = []
            for field, f_errors in form.errors.items():
                field_label = form.fields[field].label if field in form.fields else field
                errors.append(f"{field_label}: {', '.join(f_errors)}")
            return JsonResponse({'success': False, 'message': 'Error de validaci처n:\n' + '\n'.join(errors)}, status=400)
    return JsonResponse({'success': False, 'message': 'M챕todo no permitido'}, status=405)
